-- HUD.local.lua\n-- Script del HUD (Interfaz)\n-- Va en StarterGui > ScreenGui > LocalScript\n\nlocal ReplicatedStorage = game:GetService(\"ReplicatedStorage\")\nlocal Players = game:GetService(\"Players\")\nlocal player = Players.LocalPlayer\nlocal playerGui = player:WaitForChild(\"PlayerGui\")\nlocal leaderstats = player:WaitForChild(\"leaderstats\")\n\n-- Importar módulos\nlocal MoneyModule = require(ReplicatedStorage:WaitForChild(\"MoneyModule\"))\nlocal MissionModule = require(ReplicatedStorage:WaitForChild(\"MissionModule\"))\n\n-- Crear GUI\nlocal screenGui = Instance.new(\"ScreenGui\")\nscreenGui.Name = \"MainHUD\"\nscreenGui.ResetOnSpawn = false\nscreenGui.Parent = playerGui\n\n-- Crear TextLabel para dinero\nlocal moneyLabel = Instance.new(\"TextLabel\")\nmoneyLabel.Name = \"MoneyLabel\"\nmoneyLabel.Size = UDim2.new(0, 300, 0, 50)\nmoneyLabel.Position = UDim2.new(0, 20, 0, 20)\nmoneyLabel.BackgroundColor3 = Color3.fromRGB(0, 0, 0)\nmoneyLabel.TextColor3 = Color3.fromRGB(0, 255, 0)\nmoneyLabel.TextSize = 24\nmoneyLabel.Parent = screenGui\n\n-- Crear TextLabel para nivel\nlocal levelLabel = Instance.new(\"TextLabel\")\nlevelLabel.Name = \"LevelLabel\"\nlevelLabel.Size = UDim2.new(0, 300, 0, 50)\nlevelLabel.Position = UDim2.new(0, 20, 0, 80)\nlevelLabel.BackgroundColor3 = Color3.fromRGB(0, 0, 0)\nlevelLabel.TextColor3 = Color3.fromRGB(255, 255, 255)\nlevelLabel.TextSize = 24\nlevelLabel.Parent = screenGui\n\n-- Crear TextLabel para misión\nlocal missionLabel = Instance.new(\"TextLabel\")\nmissionLabel.Name = \"MissionLabel\"\nmissionLabel.Size = UDim2.new(0, 400, 0, 50)\nmissionLabel.Position = UDim2.new(0.5, -200, 0, 20)\nmissionLabel.BackgroundColor3 = Color3.fromRGB(0, 0, 0)\nmissionLabel.TextColor3 = Color3.fromRGB(255, 200, 0)\nmissionLabel.TextSize = 20\nmissionLabel.Parent = screenGui\n\n-- Actualizar información cada frame\nlocal RunService = game:GetService(\"RunService\")\n\nRunService.RenderStepped:Connect(function()\n\t-- Actualizar dinero\n\tlocal money = leaderstats:FindFirstChild(\"Dinero\")\n\tif money then\n\t\tmoneyLabel.Text = \"💰 Dinero: $\" .. money.Value\n\tend\n\t\n\t-- Actualizar nivel y XP\n\tlocal level = leaderstats:FindFirstChild(\"Nivel\")\n\tlocal xp = leaderstats:FindFirstChild(\"XP\")\n\tif level and xp then\n\t\tlevelLabel.Text = \"⭐ Nivel: \" .. level.Value .. \" | XP: \" .. xp.Value\n\tend\n\t\n\t-- Actualizar misión\n\tlocal currentMission = MissionModule:GetCurrentMission(player)\n\tif currentMission then\n\t\tmissionLabel.Text = \"📋 Misión: \" .. currentMission.title .. \" (Progreso: \" .. math.floor((currentMission.progress / currentMission.target_value) * 100) .. \"%)\"\n\telse\n\t\tmissionLabel.Text = \"📋 Sin misión activa\"\n\tend\nend)\n\nprint(\"[HUD] Interfaz cargada\")\n", "path": "scripts/HUD.local.lua